VALUES
  ('police-b20a8cf8-moex-00214', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '司法警察基於偵防犯罪需要，可廣為情報諮詢布置。下列情報諮詢作法，何者錯誤？', '["遴選諮詢對象，應視實際需要審慎遴選，慎防被反諮詢", "夜市、機場、醫院、資源回收業應定為重點諮詢地點", "諮詢人員提供情報線索，因而偵破重大案件時，應予以適當獎勵及支應必要費用", "凡經遴選諮詢工作請求合作之對象，應保護其人身安全，必要時得給予證明文件"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "61664e7f5c9b", "answer_pdf_sha1": "be41f2141576", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00215', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '犯罪現場之茶杯上採得DNA，經比對結果與甲之DNA相符，可證明甲：', '["發生時在犯罪現場", "曾碰觸該水杯", "是被害人親友", "是犯罪行為人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "61664e7f5c9b", "answer_pdf_sha1": "be41f2141576", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00216', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關刑案現場逮捕犯罪嫌疑人之情況，下列應注意事項何者錯誤？', '["犯罪嫌疑人可能仍留於現場或混跡於圍觀群眾之中，應縝密巡視觀察", "逮捕時得附帶搜索其身體、所使用之交通工具及立即可觸及之處所", "於刑案現場以外之處所逮捕時，應立即帶回現場確認犯罪事證", "遇犯罪嫌疑人攜帶或藏放之證物，應立即扣押或留存"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "61664e7f5c9b", "answer_pdf_sha1": "be41f2141576", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00217', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關刑案現場之查訪及調查分工，下列何者錯誤？', '["現場遇有非病死或可疑為非病死案件，應即照相或錄影，並通報檢察官相驗", "現場應依任務需要，將現有人員（擔任警戒任務者外）區分為調查組及勘察組", "現場調查組應對案發當時之天候、風向、氣溫、照明等進行必要之觀察", "重大刑案現場由管轄警察局刑警大隊長或其代理人擔任現場指揮官"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "61664e7f5c9b", "answer_pdf_sha1": "be41f2141576", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00218', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '實施犯罪調查，必要時得封鎖犯罪現場，並為即時之勘察。下列敘述何者正確？', '["封鎖現場時，應派員於封鎖線內警戒。非經現場指揮官同意，任何人不得進入", "現場警戒人員，不得以照相、錄影或錄音等方式觀察記錄圍觀群眾之可疑動靜", "現場封鎖範圍及層數，應視現場環境及事實需要而定", "初期封鎖之範圍應窄，待初步勘察後，再行界定三層封鎖範圍"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "61664e7f5c9b", "answer_pdf_sha1": "be41f2141576", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00219', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '司法警察偵查犯罪過程之通知、詢問，下列敘述何者錯誤？', '["通知書指派員警送達者，應於例假日之日間行之", "案件未經調查且非有必要，不得任意通知犯罪嫌疑人到場", "犯罪嫌疑人受合法通知，無正當理由不到場，得報請檢察官核發拘票", "詢問被告或犯罪嫌疑人時應全程連續錄音"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "61664e7f5c9b", "answer_pdf_sha1": "be41f2141576", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00220', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關偵辦網路犯罪案件之敘述，下列何者錯誤？', '["以網路犯罪被害人上網發生權益受損之上網所在地之警察機關為管轄機關", "網路上身分極易偽造、變造、匿名及被冒用，搜索應審慎為之，以免影響受搜索人權益", "於網路犯罪之電腦執行搜索時，應請受搜索人親自操作電腦，確保證據具備法庭效力", "執行扣押時以扣押整套電腦設備為宜，包含電腦主機、螢幕、鍵盤、電源線等設備"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "61664e7f5c9b", "answer_pdf_sha1": "be41f2141576", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00221', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '司法警察處理刑案應秉持同理心及尊重態度，關懷協助被害人及家屬。下列保護被害人規定事 項，何者錯誤？', '["被害人受傷案件，應儘速協助及護送就醫，並適時將送往之醫院通知其家屬", "被害人死亡現場應立即實施封鎖，以帷幕及屍布將屍體遮蔽", "為保護被害人家屬隱私，並維持偵查保密性，應嚴密防止讓其接受新聞媒體採訪", "審酌案情及被害人身心狀況，得利用遮蔽設備，將被害人與被告、第三人適當隔離，並對被害 人充分說明詢問案情之必要性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "61664e7f5c9b", "answer_pdf_sha1": "be41f2141576", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00222', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '實施犯罪偵查，在清查人之過程中，應把握偵查要領，發現下列何者情況尤其應特別注意？', '["案發後，關係人突告失蹤者", "案發後，左鄰右舍討論本案者", "案發前，突然生活奢華，吃喝玩樂者", "不具地緣關係之治安顧慮人口"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "61664e7f5c9b", "answer_pdf_sha1": "be41f2141576", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00223', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '犯罪偵查常需搭配跟蹤、監視等偵查作為，下列敘述何者違背正常偵查原則？', '["跟蹤及監視之目的在於發現犯罪嫌疑人之活動及身分等相關訊息", "跟蹤或監視人員應避免穿戴引人注目之衣服或特殊物件", "跟蹤屬流動或靜態觀察，係偵查人員以隱性徒步或車輛跟隨偵查對象", "被跟蹤對象在行進間突然轉身反顧是否有人監視跟蹤時，執行人員應保持自然繼續行走"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "61664e7f5c9b", "answer_pdf_sha1": "be41f2141576", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
